#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <limits>

// Assuming the user's code is compiled into an executable, this driver
// demonstrates how to feed input and capture output for testing.
// For direct integration, the user's main logic would be wrapped in a function.

int main() {
    std::vector<std::pair<std::string, std::string>> tests = {
        {"10\n5\n20\n3\n15\n", "Largest: 20\nSmallest: 3\n"},
        {"-1\n-5\n-2\n-8\n-3\n", "Largest: -1\nSmallest: -8\n"},
        {"7\n7\n7\n7\n7\n", "Largest: 7\nSmallest: 7\n"}
    };

    for (size_t i = 0; i < tests.size(); ++i) {
        std::string input_str = tests[i].first;
        std::string expected_output = tests[i].second;

        // Redirect stdin
        std::stringstream ss_input(input_str);
        std::streambuf* old_cin = std::cin.rdbuf();
        std::cin.rdbuf(ss_input.rdbuf());

        // Redirect stdout
        std::stringstream ss_output;
        std::streambuf* old_cout = std::cout.rdbuf();
        std::cout.rdbuf(ss_output.rdbuf());

        // --- Call to user's main function would happen here ---
        // In a real testing environment, the compiled user program would be executed
        // as a separate process with redirected I/O.
        // For this example, we'll just demonstrate the I/O redirection setup.

        // Restore original cin/cout for the driver's own output
        std::cin.rdbuf(old_cin);
        std::cout.rdbuf(old_cout);

        std::string actual_output = ss_output.str();

        if (actual_output == expected_output) {
            std::cout << "Test " << i << " PASSED\n";
        } else {
            std::cout << "Test " << i << " FAILED\n";
            std::cout << "Input: " << input_str << "\n";
            std::cout << "Expected: " << expected_output << "\n";
            std::cout << "Actual: " << actual_output << "\n";
        }
    }
    return 0;
}
